+    init_cargo_project(
+        &root,
+        r#"use std::time::Duration;
+
+fn main() {
+    println!("dev-test-server-start");
+    std::thread::sleep(Duration::from_secs(60));
+}"#,
+    );
+
+    let (mut child, rx) = spawn_dev(&[
